# ============================================================
# Atlantic Forest pollination project
#
# Purpose
# - Read the canonical inputs generated by 01_prepare_pam_grid_inputs.R
#   and by the Google Earth Engine MapBiomas step.
# - Calculate municipal pollination demand, EV, APEV and RV.
# - Redistribute municipal values dasymetrically to 5-km grid cells.
# - Estimate potential habitat supply, risk and demand-supply mismatch.
# - Identify critical hotspots, concentration patterns, crop drivers,
#   correlations and article tables.
#
# Important
# - Run this script from the project root, i.e. the folder that contains
#   data_raw/ and output_mata_atlantica/.
# ============================================================

# ------------------------------------------------------------
# 0) Packages
# ------------------------------------------------------------
required_packages <- c(
  "sf", "dplyr", "readr", "tidyr", "stringr", "readxl", "tibble", "janitor"
)

missing_packages <- setdiff(required_packages, rownames(installed.packages()))
if (length(missing_packages) > 0) {
  stop(
    "Please install the missing packages before running this script: ",
    paste(missing_packages, collapse = ", ")
  )
}

invisible(lapply(required_packages, library, character.only = TRUE))

# ------------------------------------------------------------
# 1) Paths and input files
# ------------------------------------------------------------
raw_dir <- "data_raw"
output_dir <- "output_mata_atlantica"

tab_dir <- file.path(output_dir, "tables")

# Figures are generated by the next script.
dir.create(output_dir, showWarnings = FALSE, recursive = TRUE)
dir.create(tab_dir, showWarnings = FALSE, recursive = TRUE)

# Canonical raw input produced by the GEE MapBiomas step.
file_mapbiomas_grid <- file.path(
  raw_dir,
  "mapbiomas_grid_atlantic_forest_2024.csv"
)

# Canonical outputs produced by 01_prepare_pam_grid_inputs.R.
file_grid <- file.path(
  output_dir,
  "atlantic_forest_grid_5km.gpkg"
)

file_pam_dependence <- file.path(
  output_dir,
  "pam_atlantic_forest_long_2020_2024_dependence.csv"
)

# Canonical raw reference table.
file_dependence_reference <- file.path(
  raw_dir,
  "pollination_dependence_reference.xlsx"
)

required_files <- c(
  file_mapbiomas_grid,
  file_grid,
  file_pam_dependence,
  file_dependence_reference
)

missing_files <- required_files[!file.exists(required_files)]
if (length(missing_files) > 0) {
  stop(
    "The following required files were not found. Check file names and run order:\n",
    paste(missing_files, collapse = "\n")
  )
}

# ------------------------------------------------------------
# 2) Global definitions
# ------------------------------------------------------------

main_dependence_levels <- c("essential", "high", "modest")

# BRL per 1 USD. Replaced with official annual mean PTAX/BCB values.
exchange_rates <- tibble::tribble(
  ~year, ~brl_per_usd,
  2020, 5.16,
  2021, 5.40,
  2022, 5.16,
  2023, 4.99,
  2024, 5.39
)

# ------------------------------------------------------------
# 3) Read input data
# ------------------------------------------------------------

# MapBiomas/GEE output keeps original Portuguese column names.
# They are converted to English internal names here.
grid_municipality_area <- readr::read_csv(file_mapbiomas_grid, show_col_types = FALSE) %>%
  janitor::clean_names() %>%
  dplyr::transmute(
    grid_id = as.character(id_grid),
    municipality_code = stringr::str_extract(as.character(codigo_municipio), "\\d{7}"),
    municipality_name = as.character(municipio),
    state_code = as.character(code_state),
    state_abbrev = as.character(abbrev_state),
    intersection_area_ha = as.numeric(area_inter_ha),
    agricultural_area_grid_municipality_ha = as.numeric(area_agri_gym_ha),
    native_area_grid_municipality_ha = as.numeric(area_nativa_gym_ha)
  )

grid <- sf::st_read(file_grid, quiet = TRUE) %>%
  janitor::clean_names()

if ("grid_id" %in% names(grid)) {
  grid <- grid %>%
    dplyr::mutate(grid_id = as.character(grid_id))
} else if ("id_grid" %in% names(grid)) {
  grid <- grid %>%
    dplyr::mutate(grid_id = as.character(id_grid)) %>%
    dplyr::select(-dplyr::any_of("id_grid"))
} else {
  stop("The grid layer must contain either 'grid_id' or 'id_grid'.")
}

# This file was written by 01_prepare_pam_grid_inputs.R with English column names.
pam_records <- readr::read_csv(file_pam_dependence, show_col_types = FALSE) %>%
  janitor::clean_names() %>%
  dplyr::transmute(
    year = as.integer(year),
    crop_type = as.character(crop_type),
    municipality_code = stringr::str_extract(as.character(municipality_code), "\\d{7}"),
    municipality_name = as.character(municipality_name),
    crop_code = as.character(crop_code),
    crop_name = as.character(crop_name),
    variable_code = as.character(variable_code),
    variable_name = as.character(variable_name),
    value = as.numeric(value)
  )

dependence_ref_raw <- readxl::read_excel(file_dependence_reference)

# ------------------------------------------------------------
# 4) Input field checks
# ------------------------------------------------------------

required_grid_municipality_columns <- c(
  "grid_id", "municipality_code", "municipality_name", "state_code", "state_abbrev",
  "intersection_area_ha", "agricultural_area_grid_municipality_ha",
  "native_area_grid_municipality_ha"
)

missing_grid_municipality_columns <- setdiff(
  required_grid_municipality_columns,
  names(grid_municipality_area)
)

if (length(missing_grid_municipality_columns) > 0) {
  stop(
    "Missing columns in grid_municipality_area: ",
    paste(missing_grid_municipality_columns, collapse = ", ")
  )
}

if (any(is.na(grid$grid_id))) {
  stop("The grid layer must contain a valid grid_id/id_grid field.")
}

# ============================================================
# PART 1 — UPDATED CROP POLLINATION DEPENDENCE
# ============================================================

# ------------------------------------------------------------
# 5) Check duplicated crop codes before removing duplicates
# ------------------------------------------------------------

duplicated_crop_codes_reference <- dependence_ref_raw %>%
  dplyr::transmute(
    crop_code = as.character(`IBGE crop code`)
  ) %>%
  dplyr::count(crop_code) %>%
  dplyr::filter(n > 1)

if (nrow(duplicated_crop_codes_reference) > 0) {
  print(duplicated_crop_codes_reference)
  stop("There are duplicated crop_code values in pollination_dependence_reference.xlsx.")
}

# ------------------------------------------------------------
# 6) Standardize the new pollination dependence table
# ------------------------------------------------------------

dependence_ref <- dependence_ref_raw %>%
  janitor::clean_names() %>%
  dplyr::transmute(
    crop_code = as.character(ibge_crop_code),
    crop_name_english = as.character(crop_name_english),
    pam_crop_name_reference = as.character(original_pam_crop_name),
    pollination_dependence_original = as.character(pollination_dependence),
    pollination_dependence = pollination_dependence_original %>%
      stringr::str_to_lower() %>%
      stringr::str_squish(),
    dependence_score = as.numeric(
      stringr::str_replace(as.character(dependence_score), ",", ".")
    ),
    classification_reference = as.character(reference)
  ) %>%
  dplyr::mutate(
    pollination_dependence = dplyr::case_when(
      pollination_dependence == "essential" ~ "essential",
      pollination_dependence == "high" ~ "high",
      pollination_dependence == "modest" ~ "modest",
      pollination_dependence == "little" ~ "little",
      pollination_dependence == "no increase" ~ "no increase",
      TRUE ~ NA_character_
    )
  ) %>%
  dplyr::distinct(crop_code, .keep_all = TRUE)

# ------------------------------------------------------------
# 7) Quality checks for dependence table
# ------------------------------------------------------------

dependence_class_audit <- dependence_ref %>%
  count(
    pollination_dependence_original,
    pollination_dependence,
    dependence_score,
    sort = TRUE
  )

print(dependence_class_audit)

dependence_problem_records <- dependence_ref %>%
  filter(
    is.na(pollination_dependence) |
      is.na(dependence_score)
  )

if (nrow(dependence_problem_records) > 0) {
  print(dependence_problem_records)
  stop("Some rows in pollination_dependence_reference.xlsx have missing dependence class or score.")
}

# ------------------------------------------------------------
# 8) Standardize PAM and replace old dependence classification
# ------------------------------------------------------------
# Important:
# - The new dependence table replaces previous dependence columns.
# - Crops not found in dependence_ref remain with NA dependence and NA score.
# - Undefined crops are excluded from PD and APEV calculations.
# - Undefined crops remain in EV, because EV is total agricultural production
#   value based on all PAM crops with production value records.

pam <- pam_records %>%
  dplyr::mutate(
    year = as.integer(year),
    municipality_code = as.character(municipality_code),
    crop_code = as.character(crop_code),
    value = as.numeric(value),
    variable_name_clean = variable_name %>%
      stringr::str_to_lower() %>%
      iconv(from = "UTF-8", to = "ASCII//TRANSLIT") %>%
      stringr::str_replace_all("[^[:alnum:]]+", " ") %>%
      stringr::str_squish()
  ) %>%
  dplyr::filter(
    year %in% 2020:2024,
    crop_code != "0"
  ) %>%
  dplyr::select(
    -dplyr::any_of(c(
      "pollination_dependence",
      "dependence_score",
      "classification_reference",
      "crop_name_english",
      "pam_crop_name_reference",
      "pollination_dependence_original"
    ))
  ) %>%
  dplyr::left_join(dependence_ref, by = "crop_code") %>%
  dplyr::mutate(
    has_defined_dependence = !is.na(pollination_dependence),
    pollination_dependence = factor(
      pollination_dependence,
      levels = c(
        "essential",
        "high",
        "modest",
        "little",
        "no increase"
      )
    ),
    is_main_pollination_crop =
      as.character(pollination_dependence) %in% main_dependence_levels
  )

# ------------------------------------------------------------
# 9) Check PAM crops without reference in the new table
# ------------------------------------------------------------

pam_crops_missing_reference <- pam_records %>%
  mutate(crop_code = as.character(crop_code)) %>%
  filter(crop_code != "0") %>%
  distinct(crop_code, crop_name) %>%
  anti_join(dependence_ref, by = "crop_code") %>%
  arrange(crop_name)

# ------------------------------------------------------------
# 10) Check final crop dependence used in PAM
# ------------------------------------------------------------

pam_dependence_audit <- pam %>%
  distinct(
    crop_code,
    crop_name,
    pollination_dependence,
    dependence_score,
    classification_reference,
    has_defined_dependence,
    is_main_pollination_crop
  ) %>%
  arrange(desc(dependence_score), crop_name)

print(
  pam_dependence_audit %>%
    count(
      pollination_dependence,
      dependence_score,
      has_defined_dependence,
      is_main_pollination_crop
    )
)

# ============================================================
# PART A — MUNICIPAL POLLINATION DEMAND
# ============================================================

# ------------------------------------------------------------
# 11) Select production quantity
# ------------------------------------------------------------

pam_quantity_all <- pam %>%
  filter(variable_name_clean == "quantidade produzida")

# Main analysis includes only essential, high and modest dependence.
pam_quantity_main <- pam_quantity_all %>%
  filter(is_main_pollination_crop)

# ------------------------------------------------------------
# 12) Annual municipal pollination demand
# PD_imy = Q_imy * D_i
# PD_my  = sum_i(Q_imy * D_i)
# ------------------------------------------------------------

municipal_demand_year <- pam_quantity_main %>%
  mutate(
    production_quantity = value,
    pollination_demand_crop = production_quantity * dependence_score
  ) %>%
  group_by(year, municipality_code, municipality_name) %>%
  summarise(
    production_main_total = sum(production_quantity, na.rm = TRUE),
    pollination_demand = sum(pollination_demand_crop, na.rm = TRUE),
    n_main_pollination_crops =
      n_distinct(crop_code[production_quantity > 0]),
    .groups = "drop"
  )

# ------------------------------------------------------------
# 13) Mean municipal demand, 2020–2024
# ------------------------------------------------------------

municipal_demand_mean <- municipal_demand_year %>%
  group_by(municipality_code, municipality_name) %>%
  summarise(
    production_main_total_mean_2020_2024 =
      mean(production_main_total, na.rm = TRUE),
    PD_mean_2020_2024 =
      mean(pollination_demand, na.rm = TRUE),
    n_main_crops_mean_2020_2024 =
      mean(n_main_pollination_crops, na.rm = TRUE),
    .groups = "drop"
  )

# ============================================================
# PART B — ECONOMIC VALUE OF AGRICULTURAL PRODUCTION
# ============================================================

# ------------------------------------------------------------
# 14) Select production value
# ------------------------------------------------------------
# EV is total agricultural production value and includes all PAM crops.
# APEV is calculated only for the main pollinator-dependent crop set:
# essential, high and modest.

pam_value_all <- pam %>%
  filter(variable_name == "Valor da produção")

# ------------------------------------------------------------
# 15) Annual EV, APEV and RV in thousand BRL
# EV_my   = sum_i(V_imy), using all crops
# APEV_my = sum_i(V_imy * D_i), using only main dependence crops
# RV_my   = APEV_my / EV_my * 100
# ------------------------------------------------------------

municipal_economic_year_brl <- pam_value_all %>%
  mutate(
    value_brl_thousand = value,
    pollination_value_brl_thousand = ifelse(
      is_main_pollination_crop,
      value_brl_thousand * dependence_score,
      0
    )
  ) %>%
  group_by(year, municipality_code, municipality_name) %>%
  summarise(
    EV_brl_thousand =
      sum(value_brl_thousand, na.rm = TRUE),
    APEV_brl_thousand =
      sum(pollination_value_brl_thousand, na.rm = TRUE),
    n_crops_total_economic =
      n_distinct(crop_code[value_brl_thousand > 0]),
    n_main_pollination_crops_economic =
      n_distinct(
        crop_code[
          is_main_pollination_crop &
            value_brl_thousand > 0
        ]
      ),
    .groups = "drop"
  ) %>%
  mutate(
    RV_percent = ifelse(
      EV_brl_thousand > 0,
      APEV_brl_thousand / EV_brl_thousand * 100,
      NA_real_
    )
  )

# ------------------------------------------------------------
# 16) Convert EV and APEV to USD
# ------------------------------------------------------------

municipal_economic_year <- municipal_economic_year_brl %>%
  left_join(exchange_rates, by = "year") %>%
  mutate(
    EV_usd = (EV_brl_thousand * 1000) / brl_per_usd,
    APEV_usd = (APEV_brl_thousand * 1000) / brl_per_usd
  )

# ------------------------------------------------------------
# 17) Mean EV, APEV and RV, 2020–2024
# ------------------------------------------------------------

municipal_economic_mean <- municipal_economic_year %>%
  group_by(municipality_code, municipality_name) %>%
  summarise(
    EV_usd_mean_2020_2024 =
      mean(EV_usd, na.rm = TRUE),
    APEV_usd_mean_2020_2024 =
      mean(APEV_usd, na.rm = TRUE),
    RV_percent_mean_2020_2024 =
      mean(RV_percent, na.rm = TRUE),
    EV_brl_thousand_mean_2020_2024 =
      mean(EV_brl_thousand, na.rm = TRUE),
    APEV_brl_thousand_mean_2020_2024 =
      mean(APEV_brl_thousand, na.rm = TRUE),
    n_crops_total_economic_mean_2020_2024 =
      mean(n_crops_total_economic, na.rm = TRUE),
    n_main_pollination_crops_economic_mean_2020_2024 =
      mean(n_main_pollination_crops_economic, na.rm = TRUE),
    .groups = "drop"
  )

# Annual totals used in Results section 3.1.
econ_year_total <- municipal_economic_year %>%
  group_by(year) %>%
  summarise(
    EV_usd_total = sum(EV_usd, na.rm = TRUE),
    APEV_usd_total = sum(APEV_usd, na.rm = TRUE),
    RV_percent_total = ifelse(
      EV_usd_total > 0,
      APEV_usd_total / EV_usd_total * 100,
      NA_real_
    ),
    .groups = "drop"
  )

# ============================================================
# PART C — SPATIAL REDISTRIBUTION USING A_gym
# ============================================================

# ------------------------------------------------------------
# 18) Agricultural and native area by municipality
# A_gym = agricultural area of municipality m inside grid g
# ------------------------------------------------------------

municipal_area <- grid_municipality_area %>%
  group_by(municipality_code) %>%
  summarise(
    agricultural_area_municipality_ha =
      sum(agricultural_area_grid_municipality_ha, na.rm = TRUE),
    native_area_municipality_ha =
      sum(native_area_grid_municipality_ha, na.rm = TRUE),
    .groups = "drop"
  )

# ------------------------------------------------------------
# 19) Redistribute mean PD, EV and APEV to grid × municipality
# PD_gm = PD_m * A_gm / sum_g(A_gm)
# EV_gm and APEV_gm follow the same dasymetric allocation.
# ------------------------------------------------------------

grid_municipality_allocated <- grid_municipality_area %>%
  left_join(municipal_area, by = "municipality_code") %>%
  left_join(
    municipal_demand_mean %>%
      select(
        municipality_code,
        production_main_total_mean_2020_2024,
        PD_mean_2020_2024,
        n_main_crops_mean_2020_2024
      ),
    by = "municipality_code"
  ) %>%
  left_join(
    municipal_economic_mean %>%
      select(
        municipality_code,
        EV_usd_mean_2020_2024,
        APEV_usd_mean_2020_2024,
        RV_percent_mean_2020_2024
      ),
    by = "municipality_code"
  ) %>%
  mutate(
    agricultural_area_share_municipality = ifelse(
      agricultural_area_municipality_ha > 0,
      agricultural_area_grid_municipality_ha / agricultural_area_municipality_ha,
      0
    ),
    PD_gym_mean_2020_2024 =
      PD_mean_2020_2024 * agricultural_area_share_municipality,
    production_main_gym_mean_2020_2024 =
      production_main_total_mean_2020_2024 * agricultural_area_share_municipality,
    EV_usd_gym_mean_2020_2024 =
      EV_usd_mean_2020_2024 * agricultural_area_share_municipality,
    APEV_usd_gym_mean_2020_2024 =
      APEV_usd_mean_2020_2024 * agricultural_area_share_municipality
  ) %>%
  mutate(
    across(
      c(
        PD_gym_mean_2020_2024,
        production_main_gym_mean_2020_2024,
        EV_usd_gym_mean_2020_2024,
        APEV_usd_gym_mean_2020_2024
      ),
      ~ tidyr::replace_na(.x, 0)
    )
  )

# ------------------------------------------------------------
# 20) Check whether municipal demand was preserved
# ------------------------------------------------------------

redistribution_check <- grid_municipality_allocated %>%
  group_by(municipality_code) %>%
  summarise(
    PD_municipal_original =
      first(tidyr::replace_na(PD_mean_2020_2024, 0)),
    PD_redistributed =
      sum(PD_gym_mean_2020_2024, na.rm = TRUE),
    agricultural_area_municipality_ha =
      first(agricultural_area_municipality_ha),
    difference =
      PD_municipal_original - PD_redistributed,
    .groups = "drop"
  )

redistribution_summary <- redistribution_check %>%
  summarise(
    PD_original_total =
      sum(PD_municipal_original, na.rm = TRUE),
    PD_redistributed_total =
      sum(PD_redistributed, na.rm = TRUE),
    difference_total =
      PD_original_total - PD_redistributed_total,
    percent_lost = ifelse(
      PD_original_total > 0,
      difference_total / PD_original_total * 100,
      NA_real_
    )
  )

# ============================================================
# PART D — GRID-LEVEL DEMAND, ECONOMIC VALUE AND SUPPLY
# ============================================================

# ------------------------------------------------------------
# 21) Aggregate allocated values by grid
# ------------------------------------------------------------

grid_attributes <- grid_municipality_allocated %>%
  group_by(grid_id) %>%
  summarise(
    intersection_area_total_ha =
      sum(intersection_area_ha, na.rm = TRUE),
    agricultural_area_ha =
      sum(agricultural_area_grid_municipality_ha, na.rm = TRUE),
    native_vegetation_area_ha =
      sum(native_area_grid_municipality_ha, na.rm = TRUE),
    PD_grid_mean_2020_2024 =
      sum(PD_gym_mean_2020_2024, na.rm = TRUE),
    production_main_grid_mean_2020_2024 =
      sum(production_main_gym_mean_2020_2024, na.rm = TRUE),
    EV_usd_grid_mean_2020_2024 =
      sum(EV_usd_gym_mean_2020_2024, na.rm = TRUE),
    APEV_usd_grid_mean_2020_2024 =
      sum(APEV_usd_gym_mean_2020_2024, na.rm = TRUE),
    n_municipal_intersections =
      n_distinct(municipality_code),
    .groups = "drop"
  ) %>%
  mutate(
    RV_percent_grid_mean_2020_2024 = ifelse(
      EV_usd_grid_mean_2020_2024 > 0,
      APEV_usd_grid_mean_2020_2024 /
        EV_usd_grid_mean_2020_2024 * 100,
      NA_real_
    )
  )

# ------------------------------------------------------------
# 22) Join attributes to grid geometry
# ------------------------------------------------------------

grid_final <- grid %>%
  left_join(grid_attributes, by = "grid_id") %>%
  mutate(
    grid_area_ha = as.numeric(sf::st_area(.)) / 10000,
    agricultural_area_ha = tidyr::replace_na(agricultural_area_ha, 0),
    native_vegetation_area_ha = tidyr::replace_na(native_vegetation_area_ha, 0),
    PD_grid_mean_2020_2024 =
      tidyr::replace_na(PD_grid_mean_2020_2024, 0),
    production_main_grid_mean_2020_2024 =
      tidyr::replace_na(production_main_grid_mean_2020_2024, 0),
    EV_usd_grid_mean_2020_2024 =
      tidyr::replace_na(EV_usd_grid_mean_2020_2024, 0),
    APEV_usd_grid_mean_2020_2024 =
      tidyr::replace_na(APEV_usd_grid_mean_2020_2024, 0),
    agricultural_proportion = agricultural_area_ha / grid_area_ha,
    native_vegetation_proportion = native_vegetation_area_ha / grid_area_ha,
    PD_density_grid = PD_grid_mean_2020_2024 / grid_area_ha,
    PD_density_agriculture = ifelse(
      agricultural_area_ha > 0,
      PD_grid_mean_2020_2024 / agricultural_area_ha,
      0
    ),
    has_agriculture = agricultural_area_ha > 1,
    has_pollination_demand = PD_grid_mean_2020_2024 > 0
  )

# Keep only grid cells with agricultural land for demand-supply analyses.
grid_agri <- grid_final %>%
  filter(has_agriculture)

# ============================================================
# PART E — POTENTIAL SUPPLY AND DEMAND–SUPPLY MISMATCH
# ============================================================

# ------------------------------------------------------------
# 23) Rescaling function
# ------------------------------------------------------------

rescale01 <- function(x) {
  rng <- range(x, na.rm = TRUE)

  if (
    is.infinite(rng[1]) ||
      is.infinite(rng[2]) ||
      diff(rng) == 0
  ) {
    return(rep(0, length(x)))
  }

  (x - rng[1]) / (rng[2] - rng[1])
}

# ------------------------------------------------------------
# 24) Calculate potential supply and mismatch
# Potential supply = proportion of native vegetation per grid cell
# Demand = log1p(PD), rescaled to 0–1
# Risk_g = Demand_std * (1 - Supply_std)
# Mismatch_g = Demand_std - Supply_std
# ------------------------------------------------------------

grid_mismatch <- grid_agri %>%
  mutate(
    habitat_agriculture_total_ha = agricultural_area_ha + native_vegetation_area_ha,
    native_supply_proportion = native_vegetation_proportion,
    habitat_agriculture_supply = ifelse(
      habitat_agriculture_total_ha > 0,
      native_vegetation_area_ha / habitat_agriculture_total_ha,
      NA_real_
    ),
    native_area_supply_log = log1p(native_vegetation_area_ha),
    demand_std = rescale01(log1p(PD_grid_mean_2020_2024)),
    supply_std = rescale01(native_supply_proportion),
    habitat_agriculture_supply_std = rescale01(habitat_agriculture_supply),
    supply_std_area = rescale01(native_area_supply_log),
    risk_deficit = demand_std * (1 - supply_std),
    mismatch = demand_std - supply_std,
    risk_deficit_habitat_agriculture = demand_std * (1 - habitat_agriculture_supply_std),
    risk_deficit_area = demand_std * (1 - supply_std_area)
  )

# ------------------------------------------------------------
# 25) Risk classes and mismatch categories
# ------------------------------------------------------------

risk_breaks <- quantile(
  grid_mismatch$risk_deficit,
  probs = c(0, 0.25, 0.5, 0.75, 1),
  na.rm = TRUE
)

q_high_demand <- quantile(
  grid_mismatch$demand_std,
  0.75,
  na.rm = TRUE
)

q_low_supply <- quantile(
  grid_mismatch$supply_std,
  0.25,
  na.rm = TRUE
)

q_high_supply <- quantile(
  grid_mismatch$supply_std,
  0.75,
  na.rm = TRUE
)

grid_mismatch <- grid_mismatch %>%
  mutate(
    risk_class = case_when(
      risk_deficit <= risk_breaks[2] ~ "low",
      risk_deficit <= risk_breaks[3] ~ "moderate",
      risk_deficit <= risk_breaks[4] ~ "high",
      TRUE ~ "very high"
    ),
    risk_class = factor(
      risk_class,
      levels = c("low", "moderate", "high", "very high")
    ),
    mismatch_category = case_when(
      demand_std >= q_high_demand &
        supply_std <= q_low_supply ~
        "high demand + low supply",
      demand_std >= q_high_demand &
        supply_std > q_low_supply ~
        "high demand + moderate/high supply",
      demand_std < q_high_demand &
        supply_std <= q_low_supply ~
        "low/moderate demand + low supply",
      demand_std < q_high_demand &
        supply_std >= q_high_supply ~
        "low/moderate demand + high supply",
      TRUE ~ "intermediate condition"
    ),
    mismatch_category = factor(
      mismatch_category,
      levels = c(
        "high demand + low supply",
        "high demand + moderate/high supply",
        "low/moderate demand + low supply",
        "low/moderate demand + high supply",
        "intermediate condition"
      )
    )
  )

# ------------------------------------------------------------
# 26) Add dominant state to each grid cell
# ------------------------------------------------------------

grid_state <- grid_municipality_area %>%
  group_by(grid_id, state_abbrev) %>%
  summarise(
    state_intersection_area_ha =
      sum(intersection_area_ha, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  group_by(grid_id) %>%
  slice_max(
    state_intersection_area_ha,
    n = 1,
    with_ties = FALSE
  ) %>%
  ungroup() %>%
  select(grid_id, state_abbrev)

grid_mismatch <- grid_mismatch %>%
  left_join(grid_state, by = "grid_id")

# ============================================================
