# ------------------------------------------------------------
# 31) Hotspot concentration by risk ranking
# ------------------------------------------------------------
# Supports Results section 3.3:
# grid cells are ranked by pollination deficit risk, and cumulative
# proportions of total PD, APEV and EV are calculated.

risk_ranked_cells <- grid_mismatch %>%
  sf::st_drop_geometry() %>%
  arrange(desc(risk_deficit)) %>%
  mutate(
    risk_rank = row_number(),
    top_fraction_cells = risk_rank / n(),
    top_percent_cells = top_fraction_cells * 100,
    cumulative_PD = cumsum(PD_grid_mean_2020_2024),
    cumulative_APEV_usd = cumsum(APEV_usd_grid_mean_2020_2024),
    cumulative_EV_usd = cumsum(EV_usd_grid_mean_2020_2024),
    cumulative_PD_percent =
      cumulative_PD /
      sum(PD_grid_mean_2020_2024, na.rm = TRUE) * 100,
    cumulative_APEV_percent =
      cumulative_APEV_usd /
      sum(APEV_usd_grid_mean_2020_2024, na.rm = TRUE) * 100,
    cumulative_EV_percent =
      cumulative_EV_usd /
      sum(EV_usd_grid_mean_2020_2024, na.rm = TRUE) * 100
  )

concentration_thresholds <- risk_ranked_cells %>%
  summarise(
    PD_top_1_percent =
      cumulative_PD_percent[which.min(abs(top_percent_cells - 1))],
    PD_top_5_percent =
      cumulative_PD_percent[which.min(abs(top_percent_cells - 5))],
    PD_top_10_percent =
      cumulative_PD_percent[which.min(abs(top_percent_cells - 10))],
    PD_top_25_percent =
      cumulative_PD_percent[which.min(abs(top_percent_cells - 25))],
    APEV_top_1_percent =
      cumulative_APEV_percent[which.min(abs(top_percent_cells - 1))],
    APEV_top_5_percent =
      cumulative_APEV_percent[which.min(abs(top_percent_cells - 5))],
    APEV_top_10_percent =
      cumulative_APEV_percent[which.min(abs(top_percent_cells - 10))],
    APEV_top_25_percent =
      cumulative_APEV_percent[which.min(abs(top_percent_cells - 25))],
    EV_top_1_percent =
      cumulative_EV_percent[which.min(abs(top_percent_cells - 1))],
    EV_top_5_percent =
      cumulative_EV_percent[which.min(abs(top_percent_cells - 5))],
    EV_top_10_percent =
      cumulative_EV_percent[which.min(abs(top_percent_cells - 10))],
    EV_top_25_percent =
      cumulative_EV_percent[which.min(abs(top_percent_cells - 25))]
  )

