    mean_native_vegetation_proportion,
    median_native_vegetation_proportion,
    sd_native_vegetation_proportion,
    mean_risk_deficit,
    median_risk_deficit,
    mean_mismatch,
    median_mismatch
  )

write_csv(
  table1_summary,
  file.path(tab_dir, "Table_1_summary_general.csv")
)

# ------------------------------------------------------------
# 57) Table S2 — Dominant crops in critical hotspots
# Table S1 is reserved above for the state-standardized hotspot table.
# ------------------------------------------------------------

table_dominant_crops_hotspots <- dominant_crop_hotspots_summary %>%
  mutate(
    PD_million = PD_total / 1e6,
    EV_usd_billion = EV_usd_total / 1e9,
    APEV_usd_billion = APEV_usd_total / 1e9
  ) %>%
  select(
    dominant_crop_grid,
    n_grid_cells,
    PD_million,
    EV_usd_billion,
    APEV_usd_billion,
    mean_dominant_crop_percent,
    mean_risk_deficit
  )

# ------------------------------------------------------------
# 58) Unique crops included in the main analysis
# ------------------------------------------------------------

unique_crops_main <- pam_quantity_main %>%
  distinct(
    crop_code,
    crop_name,
    pollination_dependence,
    dependence_score,
    classification_reference
  ) %>%
  arrange(crop_name)

# ------------------------------------------------------------
# 59) Total production by crop across all years and municipalities
# Only essential, high and modest dependence
# ------------------------------------------------------------

crop_quantity_totals <- pam_quantity_main %>%
  group_by(
    crop_code,
    crop_name,
    pollination_dependence,
    dependence_score,
    classification_reference
  ) %>%
  summarise(
    n_rows = n(),
    n_municipalities = n_distinct(municipality_code),
    n_years = n_distinct(year),
    total_quantity_2020_2024 =
      sum(value, na.rm = TRUE),
    mean_annual_quantity =
      total_quantity_2020_2024 / n_years,
    median_municipality_year_quantity =
      median(value, na.rm = TRUE),
    n_missing = sum(is.na(value)),
    .groups = "drop"
  ) %>%
  arrange(desc(total_quantity_2020_2024))


